module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
    integer i;
    reg [7:0] A_shifted;
    reg [15:0] product_temp;
    always @(*) begin
        product_temp = 0;
        A_shifted = A;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                product_temp = product_temp + (A_shifted << i);
            end
        end
    end
    always @(*) begin
        product = product_temp;
    end
endmodule
